   191→      const tierRules = ruleClassification[tier] || [];
   192→
   193→      for (const rule of tierRules) {
   194→        const match = this._evaluateRule(rule, subject, body);
   195→
   196→        if (match.matched) {
   197→          matches.push({
   198→            tier: tier,
   199→            field: rule.field,
   200→            operation: rule.operation,
   201→            values: rule.values,
