/**
 * EmailCategorizer Node: Rule Scoring
 *
 * PURPOSE
 *  Applies lexical pattern matching to email content using configured subtype rules.
 *  Implements bounded aggregation to prevent score inflation while allowing
 *  multiple patterns to contribute to category confidence.
 *
 * EXPECTED INPUT (from InitializeCandidatesNode)
 *  - Array of emails with initialized candidate_scores and baseline category data
 *  - Each item.json contains: {gmail_id, candidate_scores, hard_assertions_applied, etc.}
 *
 * CONFIGURATION (from workflow.yaml)
 *  - use_lexical_patterns: true - Apply text pattern matching
 *  - apply_subtype_rules: true - Use subtype-specific scoring
 *  - bounded_aggregation: true - Prevent score inflation with diminishing returns
 *
 * PROCESSING STEPS
 *  1. Load cached configuration from workflow static data
 *  2. For each email, iterate through all categories and their subtypes
 *  3. Apply rule-based classification patterns (high/medium/low confidence tiers)
 *  4. Calculate subtype scores with bounded aggregation
 *  5. Update category scores using max subtype score + tail support
 *  6. Track detailed scoring components for explainability
 *
 * OUTPUT
 *  - Array of email objects with updated candidate_scores
 *  - Enhanced with: {subtype_scores, rule_matches, scoring_rationale}
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class RuleScoringNode extends CodeNode {
  constructor() {
    super('RuleScoring');
  }

  async execute($input) {
    const inputItems = $input.all();
    console.log('Starting rule_scoring node execution');
    console.log(`Processing ${inputItems.length} emails for rule-based scoring`);

    // Load cached configuration from workflow static data
    const staticData = $getWorkflowStaticData('global');
    const cachedConfig = staticData.email_categorizer_config;

    if (!cachedConfig) {
      throw new Error('Email categorizer configuration not found in workflow static data');
    }

    console.log(`Found cached config with ${Object.keys(cachedConfig.config.category_lookup || {}).length} categories`);

    // Get rule scoring settings from external configuration
    const ruleScoringSettings = cachedConfig.config.processing_config?.settings?.rule_scoring || {};
    const usePattern_Matching = ruleScoringSettings.use_lexical_patterns !== false; // default true
    const applySubtypeRules = ruleScoringSettings.apply_subtype_rules !== false; // default true
    const boundedAggregation = ruleScoringSettings.bounded_aggregation !== false; // default true

    console.log(
      `Using external config - patterns: ${usePattern_Matching}, subtypes: ${applySubtypeRules}, bounded: ${boundedAggregation}`
    );

    const results = [];

    // Process each email
    for (const item of inputItems) {
      const email = item.json;
      console.log(`Rule scoring for email ${email.gmail_id}: "${email.subject?.substring(0, 50)}..."`);

      // Create enhanced result with original data plus rule scoring metadata
      const result = {
        ...email,
        candidate_scores: { ...(email.candidate_scores || {}) }, // Initialize if not present
        subtype_scores: {},
        rule_matches: {},
        scoring_rationale: {},
        pipeline_stage: 'rule_scoring',
      };

      // Get current candidate scores (from initialization stage)
      const candidateScores = { ...(email.candidate_scores || {}) };

      // Process each top-level category - check both paths in case of different config structures
      let topLevelCategories = cachedConfig.config.processing_config?.top_level_categories || {};

      // Fallback: try direct access if nested structure not found
      if (Object.keys(topLevelCategories).length === 0) {
        topLevelCategories = cachedConfig.config?.top_level_categories || {};
      }

      console.log(`Found ${Object.keys(topLevelCategories).length} top-level categories to process`);

      for (const [categoryCode, categoryData] of Object.entries(topLevelCategories)) {
        console.log(
          `Processing category '${categoryCode}' with ${Object.keys(categoryData.subtypes || {}).length} subtypes`
        );

        const subtypeScores = {};
        const categoryRuleMatches = [];
        let categoryRationale = [];

        // Process subtypes for this category
        if (applySubtypeRules && categoryData.subtypes) {
          for (const [subtypeCode, subtypeData] of Object.entries(categoryData.subtypes)) {
            const subtypeScore = this._scoreSubtype(email, subtypeData, subtypeCode);

            if (subtypeScore.score > 0) {
              subtypeScores[subtypeCode] = subtypeScore;
              categoryRuleMatches.push(...subtypeScore.matches);
              console.log(
                `Subtype '${subtypeCode}' scored ${subtypeScore.score} with ${subtypeScore.matches.length} matches`
              );
            }
          }
        }

        // Calculate aggregated category score using bounded aggregation
        let categoryScore = candidateScores[categoryCode] || 0; // Start with existing score (hard assertions, etc.)

        if (boundedAggregation && Object.keys(subtypeScores).length > 0) {
          const aggregatedScore = this._calculateBoundedAggregation(subtypeScores, categoryCode);

          // Use max of existing score vs aggregated rule score
          categoryScore = Math.max(categoryScore, aggregatedScore.totalScore);

          categoryRationale.push(`Rule aggregation: ${aggregatedScore.breakdown}`);
          console.log(
            `Category '${categoryCode}' rule score: ${aggregatedScore.totalScore} (${aggregatedScore.breakdown})`
          );
        }

        // Update results - Create proper score object structure
        result.candidate_scores[categoryCode] = {
          score: categoryScore,
          confidence: this._calculateConfidence(categoryScore, categoryRuleMatches.length),
          scoring_components: {
            rule_matches: categoryRuleMatches.map((match) => match.matched_value || match.rule_id),
            subtype_scores: subtypeScores,
            bounded_aggregation: boundedAggregation,
            total_rule_matches: categoryRuleMatches.length,
          },
          rationale:
            categoryRationale.join('; ') ||
            `Rule-based classification: ${categoryScore} points from ${categoryRuleMatches.length} matches`,
          selected_subtype_id: this._selectBestSubtype(subtypeScores),
          decision: null, // Will be set later by MultiLabelSelectionNode
        };
        result.subtype_scores[categoryCode] = subtypeScores;
        result.rule_matches[categoryCode] = categoryRuleMatches;
        result.scoring_rationale[categoryCode] = categoryRationale;
      }

      // Add summary metadata
      const totalMatches = Object.values(result.rule_matches).flat().length;
      const categoriesWithRules = Object.keys(result.subtype_scores).filter(
        (cat) => Object.keys(result.subtype_scores[cat]).length > 0
      ).length;

      result.rule_scoring_summary = {
        total_rule_matches: totalMatches,
        categories_with_rules: categoriesWithRules,
        highest_rule_score: Math.max(...Object.values(result.candidate_scores).map((scoreObj) => scoreObj.score)),
        scoring_timestamp: new Date().toISOString(),
      };

      console.log(`Rule scoring complete - ${totalMatches} matches across ${categoriesWithRules} categories`);
      results.push({ json: result });
    }

    console.log(`Rule scoring completed for ${results.length} emails`);
    console.log('Sample rule scoring summary:', results[0]?.json?.rule_scoring_summary);

    return results;
  }

  /**
   * Score a single subtype based on its rule-based classification patterns
   */
  _scoreSubtype(email, subtypeData, subtypeCode) {
    const subject = email.subject?.toLowerCase() || '';
    const body = email.body_text?.toLowerCase() || '';

    const ruleClassification = subtypeData.rule_based_classification || {};
    const matches = [];
    let totalScore = 0;

    // Process each confidence tier
    const confidenceTiers = ['high_confidence', 'medium_confidence', 'low_confidence'];

    for (const tier of confidenceTiers) {
      const tierRules = ruleClassification[tier] || [];

      for (const rule of tierRules) {
        const match = this._evaluateRule(rule, subject, body);

        if (match.matched) {
          matches.push({
            tier: tier,
            field: rule.field,
            operation: rule.operation,
            values: rule.values,
            weight: rule.weight,
            matched_value: match.matchedValue,
            rule_id: `${subtypeCode}_${tier}_${matches.length}`,
          });

          totalScore += rule.weight || 0;
          console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
        }
      }
    }

    return {
      score: totalScore,
      matches: matches,
      breakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
    };
  }

  /**
   * Evaluate a single rule against email content
   */
  _evaluateRule(rule, subject, body) {
    const fieldValue = rule.field === 'subject' ? subject : rule.field === 'body' ? body : '';

    if (!fieldValue) {
      return { matched: false, matchedValue: null };
    }

    const values = Array.isArray(rule.values) ? rule.values : [rule.values];

    switch (rule.operation) {
    case 'contains_any':
      for (const value of values) {
        if (fieldValue.includes(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'starts_with':
      for (const value of values) {
        if (fieldValue.startsWith(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'ends_with':
      for (const value of values) {
        if (fieldValue.endsWith(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'regex_any':
      for (const pattern of values) {
        try {
          const regex = new RegExp(pattern, 'i');
          const match = regex.exec(fieldValue);
          if (match) {
            return { matched: true, matchedValue: match[0] };
          }
        } catch (e) {
          console.log(`Invalid regex pattern "${pattern}": ${e.message}`);
        }
      }
      break;

    default:
      console.log(`Unknown rule operation: ${rule.operation}`);
    }

    return { matched: false, matchedValue: null };
  }

  /**
   * Calculate bounded aggregation score to prevent inflation
   * Uses diminishing returns: primary subtype + dampened tail support
   */
  _calculateBoundedAggregation(subtypeScores, _categoryCode) {
    const scores = Object.entries(subtypeScores)
      .map(([subtype, data]) => ({ subtype, score: data.score }))
      .sort((a, b) => b.score - a.score); // Sort by score descending

    if (scores.length === 0) {
      return { totalScore: 0, breakdown: 'no_subtypes' };
    }

    // Primary subtype (highest score) contributes fully
    const primaryScore = scores[0].score;
    const primarySubtype = scores[0].subtype;

    // Tail support: additional subtypes contribute with diminishing returns
    let tailSupport = 0;
    const tailContributions = [];

    if (scores.length > 1) {
      const tailScores = scores.slice(1);
      const dampingFactor = 0.3; // Each additional subtype contributes 30% of its score

      for (const tail of tailScores) {
        const contribution = tail.score * dampingFactor;
        tailSupport += contribution;
        tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
      }
    }

    const totalScore = primaryScore + tailSupport;
    const breakdown =
      `primary:${primarySubtype}:${primaryScore}` +
      (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');

    return { totalScore, breakdown };
  }

  /**
   * Calculate confidence percentage based on score and number of matches
   */
  _calculateConfidence(score, numMatches) {
    if (score === 0) return 0;

    // Basic confidence calculation: higher scores and more matches = higher confidence
    // Cap at 95% to leave room for AI enhancement
    const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
    const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%

    return Math.min(baseConfidence + matchBonus, 95);
  }

  /**
   * Select the best subtype based on scores
   */
  _selectBestSubtype(subtypeScores) {
    if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
      return null;
    }

    // Find subtype with highest score
    let bestSubtype = null;
    let bestScore = -1;

    for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
      const score = scoreData?.score || 0;
      if (score > bestScore) {
        bestScore = score;
        bestSubtype = subtypeId;
      }
    }

    return bestScore > 0 ? bestSubtype : null;
  }
}

module.exports = RuleScoringNode;

