  const node = new RuleScoringNode();

  console.log('Testing RuleScoringNode...');
  node
    .execute(mockInput)
    .then((result) => {
      console.log('✓ Test execution completed successfully');
      console.log(`✓ Processed ${result.length} emails`);

      // Save real output to sample data
      const fs = require('fs');
      const outputPath = './sample-data/05-output-rule-scoring.json';
      fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
      console.log('✓ Real output saved to:', outputPath);

      // Show detailed results for first email
      const firstResult = result[0].json;
      console.log('✓ Sample rule scoring results:');
      console.log(`  - Categories scored: ${Object.keys(firstResult.subtype_scores).length}`);
      console.log(`  - Total rule matches: ${firstResult.rule_scoring_summary.total_rule_matches}`);
      console.log(`  - Highest rule score: ${firstResult.rule_scoring_summary.highest_rule_score}`);

      // Show detailed scoring for categories with matches
      for (const [category, subtypes] of Object.entries(firstResult.subtype_scores)) {
        if (Object.keys(subtypes).length > 0) {
          console.log(
            `  - ${category}: ${
              Object.keys(subtypes).length
            } subtypes, score: ${firstResult.candidate_scores[category]}`
          );
          console.log(`    Rationale: ${firstResult.scoring_rationale[category].join('; ')}`);
        }
      }
    })
    .catch((error) => {
      console.error('✗ Test execution failed:', error.message);
      console.error(error.stack);
      process.exit(1);
    });
}

