/**
 * Execute rule-based scoring stage
 */
export function executeRuleScoring(
  email: EmailMessage,
  context: ClassificationContext,
  config: RuleScoringStageConfig
): RuleScoringStageResult {
  const startTime = Date.now();

  console.log(`Rule scoring for email ${email.id}: "${email.subject?.substring(0, 50)}..."`);

  const { settings, topLevelCategories, tuningParameters } = config;

  // Early exit if rule scoring is disabled
  if (!settings.use_lexical_patterns || !settings.apply_subtype_rules) {
    console.log('Rule scoring disabled by configuration');
    return {
      categoryResults: [],
      updatedScores: { ...context.categoryScores },
      totalMatches: 0,
      categoriesWithRules: 0,
      highestRuleScore: 0,
      processingDurationMs: Date.now() - startTime,
    };
  }

  const categoryResults: CategoryRuleResult[] = [];
  const updatedScores = { ...context.categoryScores };

  console.log(`Found ${Object.keys(topLevelCategories).length} top-level categories to process`);

  // Process each top-level category
  for (const [categoryCode, categoryData] of Object.entries(topLevelCategories)) {
    console.log(
      `Processing category '${categoryCode}' with ${Object.keys(categoryData.subtypes || {}).length} subtypes`
    );

    const subtypeScores: Record<string, SubtypeScore> = {};
    const categoryRuleMatches: RuleMatch[] = [];
    const categoryRationale: string[] = [];

    // Process subtypes for this category
    if (categoryData.subtypes) {
      for (const [subtypeCode, subtypeData] of Object.entries(categoryData.subtypes)) {
        const subtypeScore = scoreSubtype(email, subtypeData, subtypeCode, tuningParameters);

        if (subtypeScore.score > 0) {
          subtypeScores[subtypeCode] = subtypeScore;
          categoryRuleMatches.push(...subtypeScore.matches);
          console.log(
            `Subtype '${subtypeCode}' scored ${subtypeScore.score} with ${subtypeScore.matches.length} matches`
          );
        }
      }
    }

    // Calculate aggregated category score using bounded aggregation
    let categoryScore = context.categoryScores[categoryCode] || 0; // Start with existing score

    if (settings.bounded_aggregation && Object.keys(subtypeScores).length > 0) {
      const aggregatedScore = calculateBoundedAggregation(subtypeScores, tuningParameters);

      // Use max of existing score vs aggregated rule score
      categoryScore = Math.max(categoryScore, aggregatedScore.totalScore);

      categoryRationale.push(`Rule aggregation: ${aggregatedScore.breakdown}`);
      console.log(
        `Category '${categoryCode}' rule score: ${aggregatedScore.totalScore} (${aggregatedScore.breakdown})`
      );
    }

    // Calculate confidence based on score and number of matches
    const confidence = calculateConfidence(categoryScore, categoryRuleMatches.length);

    // Select best subtype
    const selectedSubtypeId = selectBestSubtype(subtypeScores);

    // Create category result
    const categoryResult: CategoryRuleResult = {
      categoryCode,
      aggregatedScore: categoryScore,
      subtypeScores,
      ruleMatches: categoryRuleMatches,
      scoringRationale:
        categoryRationale.length > 0
          ? categoryRationale
          : [`Rule-based classification: ${categoryScore} points from ${categoryRuleMatches.length} matches`],
      selectedSubtypeId,
      confidence,
    };

    categoryResults.push(categoryResult);
    updatedScores[categoryCode] = categoryScore;
  }

  // Calculate summary metrics
  const totalMatches = categoryResults.reduce((sum, result) => sum + result.ruleMatches.length, 0);
  const categoriesWithRules = categoryResults.filter((result) => Object.keys(result.subtypeScores).length > 0).length;
  const highestRuleScore = Math.max(...Object.values(updatedScores), 0);

  // Update context tracking
  const processingDurationMs = Date.now() - startTime;
  context.stageTimings['rule_scoring'] = processingDurationMs;
  context.configurationRefs['rule_scoring'] =
    'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';

  console.log(`Rule scoring complete - ${totalMatches} matches across ${categoriesWithRules} categories`);

  return {
    categoryResults,
    updatedScores,
    totalMatches,
    categoriesWithRules,
    highestRuleScore,
    processingDurationMs,
  };
}

/**
 * Score a single subtype based on its rule-based classification patterns
 */
function scoreSubtype(
  email: EmailMessage,
  subtypeData: SubtypeDefinition,
  subtypeCode: string,
  tuningParams: RuleScoringStageConfig['tuningParameters']
): SubtypeScore {
  const subject = email.subject?.toLowerCase() || '';
  const bodyText = email.bodyPlain
    ? email.bodyPlain.toLowerCase()
    : email.bodyHtml
      ? extractTextFromHtml(email.bodyHtml).toLowerCase()
      : '';

  const ruleClassification = subtypeData.rule_based_classification || {};
  const matches: RuleMatch[] = [];

  // Process each confidence tier with bounded aggregation
  const confidenceTiers: Array<{
    tier: keyof SubtypeRuleClassification;
    multiplier: number;
    maxMatches: number;
  }> = [
    { tier: 'high_confidence', multiplier: 1.0, maxMatches: tuningParams.K_high },
    { tier: 'medium_confidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.K_medium },
    { tier: 'low_confidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.K_low },
  ];

  let totalScore = 0;

  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
    const tierRules = ruleClassification[tier] || [];
    const tierMatches: RuleMatch[] = [];

    for (const rule of tierRules) {
      const match = evaluateRule(rule, subject, bodyText);

      if (match.matched) {
        tierMatches.push({
          tier,
          field: rule.field,
          operation: rule.operation,
          values: rule.values || [],
          weight: rule.weight,
          matchedValue: match.matchedValue,
          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
        });

        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
      }
    }

    // Apply bounded aggregation - take top K matches for this tier
    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);

    // Add to total score and matches
    for (const match of topMatches) {
      totalScore += match.weight * multiplier;
      matches.push(match);
    }
  }

  return {
    score: totalScore,
    matches,
    breakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
  };
}

/**
 * Evaluate a single rule against email content
 */
function evaluateRule(rule: RulePattern, subject: string, body: string): { matched: boolean; matchedValue: string } {
  let fieldValue = '';

  switch (rule.field) {
    case 'subject':
      fieldValue = subject;
      break;
    case 'body':
      fieldValue = body;
      break;
    case 'from.address':
      // This would need access to email.from, but we'll handle it in a future iteration
      fieldValue = '';
      break;
    default:
      fieldValue = '';
  }

  if (!fieldValue) {
    return { matched: false, matchedValue: '' };
  }

  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];

  switch (rule.operation) {
    case 'contains_any':
      for (const value of values) {
        if (fieldValue.includes(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'starts_with':
      for (const value of values) {
        if (fieldValue.startsWith(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'ends_with':
      for (const value of values) {
        if (fieldValue.endsWith(value.toLowerCase())) {
          return { matched: true, matchedValue: value };
        }
      }
      break;

    case 'regex_any':
      for (const pattern of values) {
        try {
          const regex = new RegExp(pattern, 'i');
          const match = regex.exec(fieldValue);
          if (match) {
            return { matched: true, matchedValue: match[0] };
          }
        } catch (e) {
          console.log(`Invalid regex pattern "${pattern}": ${e}`);
        }
      }
      break;

    case 'exists':
      return { matched: fieldValue.length > 0, matchedValue: fieldValue.substring(0, 50) };

    default:
      console.log(`Unknown rule operation: ${rule.operation}`);
  }

  return { matched: false, matchedValue: '' };
}

/**
 * Calculate bounded aggregation score to prevent inflation
 * Uses diminishing returns: primary subtype + dampened tail support
 */
function calculateBoundedAggregation(
  subtypeScores: Record<string, SubtypeScore>,
  tuningParams: RuleScoringStageConfig['tuningParameters']
): { totalScore: number; breakdown: string } {
  const scores = Object.entries(subtypeScores)
    .map(([subtype, data]) => ({ subtype, score: data.score }))
    .sort((a, b) => b.score - a.score); // Sort by score descending

  if (scores.length === 0) {
    return { totalScore: 0, breakdown: 'no_subtypes' };
  }

  // Primary subtype (highest score) contributes fully
  const primaryScore = scores[0].score;
  const primarySubtype = scores[0].subtype;

  // Tail support: additional subtypes contribute with diminishing returns
  let tailSupport = 0;
  const tailContributions: string[] = [];

  if (scores.length > 1) {
    const tailScores = scores.slice(1);

    for (const tail of tailScores) {
      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
      tailSupport += contribution;
      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
    }

    // Apply tail ratio cap
    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
    tailSupport = Math.min(tailSupport, maxTailSupport);
  }

  const totalScore = primaryScore + tailSupport;
  const breakdown =
    `primary:${primarySubtype}:${primaryScore}` +
    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');

  return { totalScore, breakdown };
}

/**
 * Calculate confidence percentage based on score and number of matches
 */
function calculateConfidence(score: number, numMatches: number): number {
  if (score === 0) return 0;

  // Basic confidence calculation: higher scores and more matches = higher confidence
  // Cap at 95% to leave room for AI enhancement
  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%

  return Math.min(baseConfidence + matchBonus, 95);
}

/**
 * Select the best subtype based on scores
 */
function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
    return null;
  }

  // Find subtype with highest score
  let bestSubtype: string | null = null;
  let bestScore = -1;

  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
    const score = scoreData?.score || 0;
    if (score > bestScore) {
      bestScore = score;
      bestSubtype = subtypeId;
    }
  }

  return bestScore > 0 ? bestSubtype : null;
}

